import{_ as s,o,c as a,ak as t}from"./chunks/framework.tZEZYUNo.js";const g=JSON.parse('{"title":"Package management and dependency rules","description":"","frontmatter":{},"headers":[],"relativePath":"package-management.md","filePath":"package-management.md"}'),n={name:"package-management.md"};function i(r,e,p,d,l,c){return o(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="package-management-and-dependency-rules" tabindex="-1">Package management and dependency rules <a class="header-anchor" href="#package-management-and-dependency-rules" aria-label="Permalink to “Package management and dependency rules”">​</a></h1><h2 id="npm-pnpm-workspaces" tabindex="-1">npm / pnpm workspaces <a class="header-anchor" href="#npm-pnpm-workspaces" aria-label="Permalink to “npm / pnpm workspaces”">​</a></h2><p>The monorepo uses <strong>pnpm</strong> with workspaces defined in <code>pnpm-workspace.yaml</code>:</p><ul><li><code>themes/*</code></li><li><code>plugins/*</code></li><li><code>packages/*</code></li><li><code>tools/*</code></li></ul><p>Root <code>package.json</code> also lists <code>workspaces</code> for compatibility with tools that read it.</p><h2 id="hoisting" tabindex="-1">Hoisting <a class="header-anchor" href="#hoisting" aria-label="Permalink to “Hoisting”">​</a></h2><p>pnpm installs dependencies into:</p><ul><li>A <strong>root</strong> <code>node_modules</code> with symlinks into workspace packages</li><li><strong>Per-package</strong> <code>node_modules</code> where needed for peer dependencies or isolation</li></ul><p><strong>Expectation:</strong> Hoisting reduces duplication, but <strong>you must not rely on implicit hoisting</strong> — a package must <strong>declare every dependency</strong> it imports in its own <code>package.json</code>. CI and fresh installs must succeed without “it worked because another package pulled it in.”</p><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to “Rules”">​</a></h2><ol><li><strong>Declare own dependencies</strong> — If <code>plugins/my-plugin/src/index.js</code> imports a package, that package must appear in <code>plugins/my-plugin/package.json</code> (<code>dependencies</code> or <code>devDependencies</code> as appropriate).</li><li><strong>Workspace protocol</strong> — Internal packages use <code>workspace:*</code> when published through the workspace (for example shared npm packages under <code>packages/</code>).</li><li><strong>Single install</strong> — Run <code>pnpm install</code> <strong>once</strong> at the monorepo root; do not ask contributors to <code>pnpm install</code> inside each plugin unless troubleshooting.</li><li><strong>Composer</strong> — Run root <code>composer install</code> for monorepo PHP tooling; run <code>pnpm composer-install</code> (or <code>nx run &lt;project&gt;:composer-install</code>) for per-project vendors as needed.</li></ol><h2 id="composer-path-repositories" tabindex="-1">Composer path repositories <a class="header-anchor" href="#composer-path-repositories" aria-label="Permalink to “Composer path repositories”">​</a></h2><p>Plugins and themes often reference monorepo libraries via a <strong>path</strong> repository in <code>composer.json</code>:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;repositories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;../../packages/phpunit-config&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;options&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;symlink&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>Keep relative paths correct for the package’s depth under <code>plugins/</code> or <code>themes/</code>.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Things to check</th></tr></thead><tbody><tr><td><strong>Module not found</strong> after adding an import</td><td>Add the dependency to that package’s <code>package.json</code> and run <code>pnpm install</code> from root.</td></tr><tr><td><strong>Wrong version</strong> of a transitive dep</td><td>Add a <strong>direct</strong> devDependency or use pnpm <code>overrides</code> at root (sparingly, with team agreement).</td></tr><tr><td><strong>Peer dependency warnings</strong></td><td>Install the peer into the package that consumes it or align versions with <code>@wordpress/*</code> packages.</td></tr><tr><td><strong>Duplicate React</strong> or block editor issues</td><td>Ensure a single version of <code>@wordpress/*</code> across the workspace; check root and package <code>package.json</code> alignment.</td></tr><tr><td><strong>Composer path not found</strong></td><td>Verify <code>url</code> in <code>composer.json</code> relative to the package directory.</td></tr></tbody></table><h2 id="lockfiles" tabindex="-1">Lockfiles <a class="header-anchor" href="#lockfiles" aria-label="Permalink to “Lockfiles”">​</a></h2><ul><li><strong><code>pnpm-lock.yaml</code></strong> is committed at the root — keep it authoritative for JS.</li><li><strong>Per-package <code>composer.lock</code></strong> — follow team policy; many migrations remove per-package locks in favor of reproducible installs from <code>composer.json</code> constraints. Confirm with maintainers before deleting.</li></ul>`,19)])])}const k=s(n,[["render",i]]);export{g as __pageData,k as default};
